#!/usr/bin/env python3
"""speak.py — pipe text to ElevenLabs TTS and play it."""
import sys
import os
import tempfile
import subprocess
import urllib.request
import urllib.error
import json

API_KEY = "sk_4249b83ff0ba12268ec38b646fc7dc06889bc7a0dc1b6d95"
VOICE_ID = "JBFqnCBsd6RMkjVDRTpX"  # "George" — change to your preferred voice ID

def speak(text: str):
    url = f"https://api.elevenlabs.io/v1/text-to-speech/{VOICE_ID}"
    payload = json.dumps({
        "text": text,
        "model_id": "eleven_turbo_v2_5",
        "voice_settings": {"stability": 0.5, "similarity_boost": 0.75}
    }).encode()

    req = urllib.request.Request(url, data=payload, headers={
        "xi-api-key": API_KEY,
        "Content-Type": "application/json",
        "Accept": "audio/mpeg"
    })

    try:
        with urllib.request.urlopen(req) as resp:
            audio = resp.read()
    except urllib.error.HTTPError as e:
        print(f"ElevenLabs error {e.code}: {e.read().decode()}", file=sys.stderr)
        sys.exit(1)

    with tempfile.NamedTemporaryFile(suffix=".mp3", delete=False) as f:
        f.write(audio)
        tmp = f.name

    subprocess.run(["ffplay", "-nodisp", "-autoexit", "-loglevel", "quiet", tmp])
    os.unlink(tmp)

if __name__ == "__main__":
    if len(sys.argv) > 1:
        speak(" ".join(sys.argv[1:]))
    else:
        text = sys.stdin.read().strip()
        if text:
            speak(text)

